use std::io::{self, Read};
use std::f64::consts::PI;

// --- realcompare (from reference) ---
fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return "EQ";
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        "GT"
    } else if diff < -eps {
        "LT"
    } else {
        "EQ"
    }
}

// --- JSON parsing (minimal, no external deps) ---

#[derive(Debug, Clone)]
enum JsonVal {
    Null,
    Bool(bool),
    Num(f64),
    Str(String),
    Arr(Vec<JsonVal>),
    Obj(Vec<(String, JsonVal)>),
}

impl JsonVal {
    fn as_f64(&self) -> f64 {
        match self {
            JsonVal::Num(n) => *n,
            _ => panic!("expected number"),
        }
    }
    fn as_i64(&self) -> i64 {
        match self {
            JsonVal::Num(n) => *n as i64,
            _ => panic!("expected number"),
        }
    }
    fn as_usize(&self) -> usize {
        self.as_i64() as usize
    }
    fn as_str_ref(&self) -> &str {
        match self {
            JsonVal::Str(s) => s.as_str(),
            _ => panic!("expected string"),
        }
    }
    fn as_arr(&self) -> &Vec<JsonVal> {
        match self {
            JsonVal::Arr(a) => a,
            _ => panic!("expected array"),
        }
    }
    fn get(&self, key: &str) -> &JsonVal {
        match self {
            JsonVal::Obj(pairs) => {
                for (k, v) in pairs {
                    if k == key {
                        return v;
                    }
                }
                panic!("key not found: {}", key);
            }
            _ => panic!("expected object"),
        }
    }
    fn as_bool(&self) -> bool {
        match self {
            JsonVal::Bool(b) => *b,
            _ => panic!("expected bool"),
        }
    }
}

struct Parser {
    chars: Vec<char>,
    pos: usize,
}

impl Parser {
    fn new(s: &str) -> Self {
        Parser {
            chars: s.chars().collect(),
            pos: 0,
        }
    }
    fn skip_ws(&mut self) {
        while self.pos < self.chars.len() && self.chars[self.pos].is_ascii_whitespace() {
            self.pos += 1;
        }
    }
    fn peek(&self) -> char {
        self.chars[self.pos]
    }
    fn next_char(&mut self) -> char {
        let c = self.chars[self.pos];
        self.pos += 1;
        c
    }
    fn parse_value(&mut self) -> JsonVal {
        self.skip_ws();
        let c = self.peek();
        match c {
            '"' => JsonVal::Str(self.parse_string()),
            '{' => self.parse_object(),
            '[' => self.parse_array(),
            't' | 'f' => self.parse_bool(),
            'n' => self.parse_null(),
            _ => self.parse_number(),
        }
    }
    fn parse_string(&mut self) -> String {
        self.next_char(); // consume "
        let mut s = String::new();
        loop {
            let c = self.next_char();
            if c == '"' {
                break;
            }
            if c == '\\' {
                let esc = self.next_char();
                match esc {
                    '"' => s.push('"'),
                    '\\' => s.push('\\'),
                    '/' => s.push('/'),
                    'n' => s.push('\n'),
                    't' => s.push('\t'),
                    'r' => s.push('\r'),
                    'u' => {
                        let mut hex = String::new();
                        for _ in 0..4 {
                            hex.push(self.next_char());
                        }
                        let code = u32::from_str_radix(&hex, 16).unwrap();
                        s.push(char::from_u32(code).unwrap_or('\u{FFFD}'));
                    }
                    _ => {
                        s.push(esc);
                    }
                }
            } else {
                s.push(c);
            }
        }
        s
    }
    fn parse_number(&mut self) -> JsonVal {
        let start = self.pos;
        if self.pos < self.chars.len() && self.chars[self.pos] == '-' {
            self.pos += 1;
        }
        while self.pos < self.chars.len() && self.chars[self.pos].is_ascii_digit() {
            self.pos += 1;
        }
        if self.pos < self.chars.len() && self.chars[self.pos] == '.' {
            self.pos += 1;
            while self.pos < self.chars.len() && self.chars[self.pos].is_ascii_digit() {
                self.pos += 1;
            }
        }
        if self.pos < self.chars.len() && (self.chars[self.pos] == 'e' || self.chars[self.pos] == 'E') {
            self.pos += 1;
            if self.pos < self.chars.len() && (self.chars[self.pos] == '+' || self.chars[self.pos] == '-') {
                self.pos += 1;
            }
            while self.pos < self.chars.len() && self.chars[self.pos].is_ascii_digit() {
                self.pos += 1;
            }
        }
        let s: String = self.chars[start..self.pos].iter().collect();
        JsonVal::Num(s.parse::<f64>().unwrap())
    }
    fn parse_bool(&mut self) -> JsonVal {
        if self.chars[self.pos..].starts_with(&['t', 'r', 'u', 'e']) {
            self.pos += 4;
            JsonVal::Bool(true)
        } else {
            self.pos += 5;
            JsonVal::Bool(false)
        }
    }
    fn parse_null(&mut self) -> JsonVal {
        self.pos += 4;
        JsonVal::Null
    }
    fn parse_array(&mut self) -> JsonVal {
        self.next_char(); // [
        self.skip_ws();
        let mut arr = Vec::new();
        if self.peek() == ']' {
            self.next_char();
            return JsonVal::Arr(arr);
        }
        loop {
            arr.push(self.parse_value());
            self.skip_ws();
            if self.peek() == ',' {
                self.next_char();
            } else {
                break;
            }
        }
        self.skip_ws();
        self.next_char(); // ]
        JsonVal::Arr(arr)
    }
    fn parse_object(&mut self) -> JsonVal {
        self.next_char(); // {
        self.skip_ws();
        let mut pairs = Vec::new();
        if self.peek() == '}' {
            self.next_char();
            return JsonVal::Obj(pairs);
        }
        loop {
            self.skip_ws();
            let key = self.parse_string();
            self.skip_ws();
            self.next_char(); // :
            let val = self.parse_value();
            pairs.push((key, val));
            self.skip_ws();
            if self.peek() == ',' {
                self.next_char();
            } else {
                break;
            }
        }
        self.skip_ws();
        self.next_char(); // }
        JsonVal::Obj(pairs)
    }
}

fn parse_json(s: &str) -> JsonVal {
    let mut p = Parser::new(s);
    p.parse_value()
}

// --- Geometry helpers ---

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0).abs()
}

fn angle_at_vertex(x1: f64, y1: f64, xv: f64, yv: f64, x3: f64, y3: f64) -> Option<f64> {
    let dx1 = x1 - xv;
    let dy1 = y1 - yv;
    let dx3 = x3 - xv;
    let dy3 = y3 - yv;
    let len1 = (dx1 * dx1 + dy1 * dy1).sqrt();
    let len3 = (dx3 * dx3 + dy3 * dy3).sqrt();
    if realcompare(len1, 0.0) == "EQ" || realcompare(len3, 0.0) == "EQ" {
        return None;
    }
    let cos_angle = (dx1 * dx3 + dy1 * dy3) / (len1 * len3);
    let clamped = cos_angle.max(-1.0).min(1.0);
    Some(clamped.acos())
}

/// Determine the quadrant of a point with priority I > II > III > IV
fn quadrant(x: f64, y: f64) -> u8 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

/// Check if three points can be contained within or on a circle of given radius
fn points_fit_in_circle(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64, radius: f64) -> bool {
    // If all three points are coincident, they fit in any circle with radius >= 0
    let d12 = dist(x1, y1, x2, y2);
    let d13 = dist(x1, y1, x3, y3);
    let d23 = dist(x2, y2, x3, y3);

    // Find the maximum side
    let max_side = d12.max(d13).max(d23);

    // If max_side/2 > radius, definitely can't fit
    // But we need to check circumradius for non-degenerate triangles

    let area = triangle_area(x1, y1, x2, y2, x3, y3);

    if realcompare(area, 0.0) == "EQ" {
        // Points are collinear: the minimum enclosing circle has diameter = max_side
        let min_radius = max_side / 2.0;
        realcompare(min_radius, radius) != "GT"
    } else {
        // Non-degenerate triangle: circumradius = (a*b*c) / (4*area)
        let circumradius = (d12 * d13 * d23) / (4.0 * area);
        realcompare(circumradius, radius) != "GT"
    }
}

/// Distance from point (px, py) to line defined by (x1, y1) and (x2, y2)
fn point_to_line_dist(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let len = (dx * dx + dy * dy).sqrt();
    if realcompare(len, 0.0) == "EQ" {
        // Line endpoints coincide, distance is point-to-point
        dist(px, py, x1, y1)
    } else {
        ((dy * px - dx * py + x2 * y1 - y2 * x1) / len).abs()
    }
}

// --- LIC implementations ---

fn lic1(x: &[f64], y: &[f64], numpoints: usize, length1: f64) -> bool {
    for i in 0..numpoints - 1 {
        let d = dist(x[i], y[i], x[i + 1], y[i + 1]);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic2(x: &[f64], y: &[f64], numpoints: usize, radius1: f64) -> bool {
    for i in 0..numpoints - 2 {
        if !points_fit_in_circle(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2], radius1) {
            return true;
        }
    }
    false
}

fn lic3(x: &[f64], y: &[f64], numpoints: usize, epsilon: f64) -> bool {
    for i in 0..numpoints - 2 {
        if let Some(angle) = angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]) {
            if realcompare(angle, PI - epsilon) == "LT" || realcompare(angle, PI + epsilon) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic4(x: &[f64], y: &[f64], numpoints: usize, area1: f64) -> bool {
    for i in 0..numpoints - 2 {
        let a = triangle_area(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2]);
        if realcompare(a, area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic5(x: &[f64], y: &[f64], numpoints: usize, q_pts: usize, quads: usize) -> bool {
    for i in 0..=numpoints - q_pts {
        let mut seen = [false; 4];
        for j in i..i + q_pts {
            let q = quadrant(x[j], y[j]);
            seen[(q - 1) as usize] = true;
        }
        let count = seen.iter().filter(|&&b| b).count();
        if count > quads {
            return true;
        }
    }
    false
}

fn lic6(x: &[f64], _y: &[f64], numpoints: usize) -> bool {
    for i in 0..numpoints - 1 {
        if realcompare(x[i + 1] - x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic7(x: &[f64], y: &[f64], numpoints: usize, n_pts: usize, dist_param: f64) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..=numpoints - n_pts {
        let first = i;
        let last = i + n_pts - 1;
        let fx = x[first];
        let fy = y[first];
        let lx = x[last];
        let ly = y[last];
        let coincident = realcompare(dist(fx, fy, lx, ly), 0.0) == "EQ";
        for k in first + 1..last {
            let d = if coincident {
                dist(x[k], y[k], fx, fy)
            } else {
                point_to_line_dist(x[k], y[k], fx, fy, lx, ly)
            };
            if realcompare(d, dist_param) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic8(x: &[f64], y: &[f64], numpoints: usize, k_pts: usize, length1: f64) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - k_pts - 1 {
        let j = i + k_pts + 1;
        let d = dist(x[i], y[i], x[j], y[j]);
        if realcompare(d, length1) == "GT" {
            return true;
        }
    }
    false
}

fn lic9(x: &[f64], y: &[f64], numpoints: usize, a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        if k >= numpoints {
            break;
        }
        if !points_fit_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], radius1) {
            return true;
        }
    }
    false
}

fn lic10(x: &[f64], y: &[f64], numpoints: usize, c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + c_pts + 1;
        let k = j + d_pts + 1;
        if k >= numpoints {
            break;
        }
        if let Some(angle) = angle_at_vertex(x[i], y[i], x[j], y[j], x[k], y[k]) {
            if realcompare(angle, PI - epsilon) == "LT" || realcompare(angle, PI + epsilon) == "GT" {
                return true;
            }
        }
    }
    false
}

fn lic11(x: &[f64], y: &[f64], numpoints: usize, e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    for i in 0..numpoints {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        if k >= numpoints {
            break;
        }
        let a = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
        if realcompare(a, area1) == "GT" {
            return true;
        }
    }
    false
}

fn lic12(x: &[f64], _y: &[f64], numpoints: usize, g_pts: usize) -> bool {
    if numpoints < 3 {
        return false;
    }
    for i in 0..numpoints - g_pts - 1 {
        let j = i + g_pts + 1;
        if realcompare(x[j] - x[i], 0.0) == "LT" {
            return true;
        }
    }
    false
}

fn lic13(x: &[f64], y: &[f64], numpoints: usize, k_pts: usize, length1: f64, length2: f64) -> bool {
    if numpoints < 3 {
        return false;
    }
    let mut cond1 = false;
    let mut cond2 = false;
    for i in 0..numpoints - k_pts - 1 {
        let j = i + k_pts + 1;
        let d = dist(x[i], y[i], x[j], y[j]);
        if realcompare(d, length1) == "GT" {
            cond1 = true;
        }
        if realcompare(d, length2) == "LT" {
            cond2 = true;
        }
        if cond1 && cond2 {
            return true;
        }
    }
    cond1 && cond2
}

fn lic14(x: &[f64], y: &[f64], numpoints: usize, a_pts: usize, b_pts: usize, radius1: f64, radius2: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    let mut cond1 = false;
    let mut cond2 = false;
    for i in 0..numpoints {
        let j = i + a_pts + 1;
        let k = j + b_pts + 1;
        if k >= numpoints {
            break;
        }
        if !cond1 && !points_fit_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], radius1) {
            cond1 = true;
        }
        if !cond2 && points_fit_in_circle(x[i], y[i], x[j], y[j], x[k], y[k], radius2) {
            cond2 = true;
        }
        if cond1 && cond2 {
            return true;
        }
    }
    cond1 && cond2
}

fn lic15(x: &[f64], y: &[f64], numpoints: usize, e_pts: usize, f_pts: usize, area1: f64, area2: f64) -> bool {
    if numpoints < 5 {
        return false;
    }
    let mut cond1 = false;
    let mut cond2 = false;
    for i in 0..numpoints {
        let j = i + e_pts + 1;
        let k = j + f_pts + 1;
        if k >= numpoints {
            break;
        }
        let a = triangle_area(x[i], y[i], x[j], y[j], x[k], y[k]);
        if !cond1 && realcompare(a, area1) == "GT" {
            cond1 = true;
        }
        if !cond2 && realcompare(a, area2) == "LT" {
            cond2 = true;
        }
        if cond1 && cond2 {
            return true;
        }
    }
    cond1 && cond2
}

// --- Main logic ---

fn decide(input: &JsonVal) -> String {
    let numpoints = input.get("numpoints").as_usize();
    let x_arr = input.get("x").as_arr();
    let y_arr = input.get("y").as_arr();
    let x: Vec<f64> = x_arr.iter().map(|v| v.as_f64()).collect();
    let y: Vec<f64> = y_arr.iter().map(|v| v.as_f64()).collect();

    let params = input.get("parameters");
    let length1 = params.get("LENGTH1").as_f64();
    let radius1 = params.get("RADIUS1").as_f64();
    let epsilon = params.get("EPSILON").as_f64();
    let area1 = params.get("AREA1").as_f64();
    let q_pts = params.get("Q_PTS").as_usize();
    let quads = params.get("QUADS").as_usize();
    let dist_param = params.get("DIST").as_f64();
    let n_pts = params.get("N_PTS").as_usize();
    let k_pts = params.get("K_PTS").as_usize();
    let a_pts = params.get("A_PTS").as_usize();
    let b_pts = params.get("B_PTS").as_usize();
    let c_pts = params.get("C_PTS").as_usize();
    let d_pts = params.get("D_PTS").as_usize();
    let e_pts = params.get("E_PTS").as_usize();
    let f_pts = params.get("F_PTS").as_usize();
    let g_pts = params.get("G_PTS").as_usize();
    let length2 = params.get("LENGTH2").as_f64();
    let radius2 = params.get("RADIUS2").as_f64();
    let area2 = params.get("AREA2").as_f64();

    // Compute CMV (0-indexed, 15 elements for LIC 1..15)
    let cmv: [bool; 15] = [
        lic1(&x, &y, numpoints, length1),
        lic2(&x, &y, numpoints, radius1),
        lic3(&x, &y, numpoints, epsilon),
        lic4(&x, &y, numpoints, area1),
        lic5(&x, &y, numpoints, q_pts, quads),
        lic6(&x, &y, numpoints),
        lic7(&x, &y, numpoints, n_pts, dist_param),
        lic8(&x, &y, numpoints, k_pts, length1),
        lic9(&x, &y, numpoints, a_pts, b_pts, radius1),
        lic10(&x, &y, numpoints, c_pts, d_pts, epsilon),
        lic11(&x, &y, numpoints, e_pts, f_pts, area1),
        lic12(&x, &y, numpoints, g_pts),
        lic13(&x, &y, numpoints, k_pts, length1, length2),
        lic14(&x, &y, numpoints, a_pts, b_pts, radius1, radius2),
        lic15(&x, &y, numpoints, e_pts, f_pts, area1, area2),
    ];

    // Parse LCM
    let lcm_arr = input.get("lcm").as_arr();
    let mut lcm = [[0u8; 15]; 15]; // 0=NOTUSED, 1=ORR, 2=ANDD
    for i in 0..15 {
        let row = lcm_arr[i].as_arr();
        for j in 0..15 {
            lcm[i][j] = match row[j].as_str_ref() {
                "NOTUSED" => 0,
                "ORR" => 1,
                "ANDD" => 2,
                _ => 0,
            };
        }
    }

    // Parse PUM diagonal
    let pum_diag_arr = input.get("pum_diag").as_arr();
    let mut pum_diag = [false; 15];
    for i in 0..15 {
        pum_diag[i] = pum_diag_arr[i].as_bool();
    }

    // Compute PUM
    let mut pum = [[false; 15]; 15];
    for i in 0..15 {
        pum[i][i] = pum_diag[i];
        for j in 0..15 {
            if i == j {
                continue;
            }
            pum[i][j] = match lcm[i][j] {
                0 => true, // NOTUSED
                1 => cmv[i] || cmv[j], // ORR
                2 => cmv[i] && cmv[j], // ANDD
                _ => true,
            };
        }
    }

    // Compute FUV
    let mut fuv = [false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            // PUM diagonal is false => LIC not considered => FUV[i] = true
            fuv[i] = true;
        } else {
            // Check if all elements in row i are true
            fuv[i] = pum[i].iter().all(|&b| b);
        }
    }

    // Compute LAUNCH
    let launch = fuv.iter().all(|&b| b);

    // Build output JSON
    let mut out = String::new();
    out.push_str("{\"cmv\":[");
    for i in 0..15 {
        if i > 0 { out.push(','); }
        out.push_str(if cmv[i] { "true" } else { "false" });
    }
    out.push_str("],\"pum\":[");
    for i in 0..15 {
        if i > 0 { out.push(','); }
        out.push('[');
        for j in 0..15 {
            if j > 0 { out.push(','); }
            out.push_str(if pum[i][j] { "true" } else { "false" });
        }
        out.push(']');
    }
    out.push_str("],\"fuv\":[");
    for i in 0..15 {
        if i > 0 { out.push(','); }
        out.push_str(if fuv[i] { "true" } else { "false" });
    }
    out.push_str("],\"launch\":");
    out.push_str(if launch { "true" } else { "false" });
    out.push('}');
    out
}

fn main() {
    let mut input_str = String::new();
    io::stdin().read_to_string(&mut input_str).unwrap();
